596	// parseRoutingHarnessModel extracts (provider, model) from a kind:routing
597	// event body. Returns ok=false when the body cannot be parsed or carries no
598	// provider, since a tier without a provider is not a useful attribution.
599	func parseRoutingHarnessModel(e bead.BeadEvent) (string, string, bool) {
600		if e.Body == "" {
601			return "", "", false
602		}
603		var body struct {
604			ResolvedProvider string `json:"resolved_provider"`
605			ResolvedModel    string `json:"resolved_model"`
606		}
607		if err := json.Unmarshal([]byte(e.Body), &body); err != nil {
608			return "", "", false
609		}
610		if body.ResolvedProvider == "" {
611			return "", "", false
612		}
613		return body.ResolvedProvider, body.ResolvedModel, true
614	}
