696	// computeCostEfficiency scans .ddx/executions/*/result.json under workingDir
697	// and aggregates per-bead cost totals. When lastN > 0, the set of beads in
698	// the output is restricted to those with at least one attempt in the most
699	// recent N executions; for those beads, *all* historical attempts contribute
700	// to the totals so escalation chains are not artificially truncated.
701	func computeCostEfficiency(workingDir string, lastN int) ([]costEfficiencyRow, error) {
702		execRoot := filepath.Join(workingDir, ".ddx", "executions")
703		entries, err := os.ReadDir(execRoot)
704		if err != nil {
705			if os.IsNotExist(err) {
706				return []costEfficiencyRow{}, nil
707			}
708			return nil, fmt.Errorf("read executions dir: %w", err)
709		}
710	
711		names := make([]string, 0, len(entries))
712		for _, entry := range entries {
713			if entry.IsDir() {
714				names = append(names, entry.Name())
715			}
716		}
717		sort.Strings(names)
718	
719		type loadedAttempt struct {
720			beadID  string
721			harness string
722			model   string
723			outcome string
724			costUSD float64
725		}
726		loaded := make([]loadedAttempt, 0, len(names))
727		for _, name := range names {
728			resultPath := filepath.Join(execRoot, name, "result.json")
729			raw, err := os.ReadFile(resultPath)
730			if err != nil {
731				continue
732			}
733			var res agent.ExecuteBeadResult
734			if err := json.Unmarshal(raw, &res); err != nil {
735				continue
736			}
737			if res.BeadID == "" {
738				continue
739			}
740			loaded = append(loaded, loadedAttempt{
741				beadID:  res.BeadID,
742				harness: res.Harness,
743				model:   res.Model,
744				outcome: res.Outcome,
745				costUSD: res.CostUSD,
746			})
747		}
748	
749		// --last N: restrict the output set to beads touched by the most recent
750		// N usable attempts. All historical attempts for those beads still
751		// contribute to totals so escalation cost is visible.
752		var includeBead map[string]bool
753		if lastN > 0 && len(loaded) > 0 {
754			includeBead = map[string]bool{}
755			start := len(loaded) - lastN
756			if start < 0 {
757				start = 0
758			}
759			for _, a := range loaded[start:] {
760				includeBead[a.beadID] = true
761			}
762		}
763	
764		type agg struct {
765			beadID            string
766			totalAttempts     int
767			totalCostUSD      float64
768			successfulCostUSD float64
769			wastedCostUSD     float64
770			finalHarness      string
771			finalModel        string
772		}
773		byBead := map[string]*agg{}
774		order := []string{}
775	
776		for _, a := range loaded {
777			if includeBead != nil && !includeBead[a.beadID] {
778				continue
779			}
780			g, ok := byBead[a.beadID]
781			if !ok {
782				g = &agg{beadID: a.beadID}
783				byBead[a.beadID] = g
784				order = append(order, a.beadID)
785			}
786			g.totalAttempts++
787			g.totalCostUSD += a.costUSD
788			if a.outcome == "task_succeeded" {
789				g.successfulCostUSD += a.costUSD
790			} else {
791				g.wastedCostUSD += a.costUSD
792			}
793			// Attempts iterate in chronological order, so the last assignment
794			// wins — that is the most recent tier tried on this bead.
795			g.finalHarness = a.harness
796			g.finalModel = a.model
797		}
798	
799		rows := make([]costEfficiencyRow, 0, len(order))
800		for _, id := range order {
801			g := byBead[id]
802			rows = append(rows, costEfficiencyRow{
803				BeadID:            g.beadID,
804				TotalAttempts:     g.totalAttempts,
805				TotalCostUSD:      g.totalCostUSD,
806				SuccessfulCostUSD: g.successfulCostUSD,
807				WastedCostUSD:     g.wastedCostUSD,
808				FinalTier:         tierKey(g.finalHarness, g.finalModel),
809				FinalHarness:      g.finalHarness,
810			})
811		}
812		sort.Slice(rows, func(i, j int) bool { return rows[i].BeadID < rows[j].BeadID })
813		return rows, nil
814	}
